// This code takes the file named 'data' in the binary area 
// and renames it to 'OriginalImage' in the binary area.

// 1. Get the current item
const item = $input.item;

// 2. Check if the binary property 'data' exists (which it should from Download Image)
if (item.binary && item.binary.data) {
    // 3. Create a new binary property named 'OriginalImage' 
    //    and set its value to the data from the 'data' property.
    item.binary.OriginalImage = item.binary.data;

    // 4. Optionally, remove the old 'data' property to clean up
    delete item.binary.data;
}

// 5. Also, ensure the JSON has a OriginalImage property that points to the metadata
//    (The metadata object is stored in the binary area itself)
if (item.binary.OriginalImage) {
    item.json.OriginalImage = item.binary.OriginalImage;
}

return item;

