// Read client info from the other node
const clientInfo = $('Get Client Info').first().json || {};

// Extract context with safe defaults
const businessName   = clientInfo.business_info?.business_name ?? '';
const businessAddress   = clientInfo.business_info?.business_address ?? '';
const businessPhone  = clientInfo.client.phone_number ?? '';
const industry       = clientInfo.business_info?.industry ?? 'general';
const brandTone      = clientInfo.business_info?.brand_tone ?? 'professional';
const primaryColor   = clientInfo.brand_assets?.primary_color ?? '#000000';
const secondaryColor = clientInfo.brand_assets?.secondary_color ?? '#FFFFFF';

// Build the prompt
const designPrompt = `
Business Name: ${businessName}
Business Address: ${businessAddress}
Phone: ${businessPhone}
Industry: ${industry}
Brand Tone: ${brandTone}
Brand Colors: Primary ${primaryColor}, Secondary ${secondaryColor}
`.trim();

// Return a single item
return {
  json: {
    prompt: designPrompt,
  }
};

const apiKey = "AIzaSyAnoTBXuKFoXP6zXjO-6doghHvG53ryFec";

const parts = [];
parts.push({ text: $json.final_prompt });

// 1) Inputs from the trigger (the parent workflow payload)
const productTrigger = $('When Executed by Another Workflow').first().json;
const logoTrigger = $('Get Client Info').first().json.brand_assets.logo_url;

// These flags decide whether to include the images
const hasProductInput = !!(productTrigger.productImage && String(productTrigger.productImage).trim().length > 0);


const hasLogoInput = !!(logoTrigger && String(logoTrigger).trim().length > 0);

// 2) If trigger says product exists -> take it from Extract node and add it
if (hasProductInput) {
  const product = $('Extract from File1').first().json?.product;

  parts.push({
    inlineData: {
      mimeType: "image/png",
      data: product,
    },
  });
}

// 3) If trigger says logo exists -> take it from Extract node and add it
if (hasLogoInput) {
  const logo = $('Extract from File').first()?.json?.logo;

  parts.push({
    inlineData: {
      mimeType: "image/png",
      data: logo,
    },
  });
}

const body = {
  contents: [{ parts }],
  generationConfig: {
    responseModalities: ["IMAGE"],
    imageConfig: { aspectRatio: "1:1", imageSize: "1K" },
  },
};

console.log("boooody", body)

const response = await this.helpers.httpRequest({
  method: "POST",
  url: "https://generativelanguage.googleapis.com/v1beta/models/gemini-3-pro-image-preview:generateContent",
  headers: {
    "x-goog-api-key": apiKey,
    "Content-Type": "application/json",
  },
  body,
  json: true,
});

return [{ json: response }];

// 1) Get the base64 image string from the Gemini response
// Adjust this path if your data sits somewhere else in your JSON
const b64 =
  $json.candidates?.[0]?.content?.parts?.find(p => p.inlineData?.data)?.inlineData?.data
  || $json.candidates?.[0]?.content?.parts?.find(p => p.inline_data?.data)?.inline_data?.data
  || $json.data; // fallback if you mapped it already

if (!b64) {
  throw new Error("No base64 image data found in response");
}

// 2) Convert base64 -> Buffer
const buffer = Buffer.from(b64, "base64");

// 3) Put into n8n binary output
return [
  {
    json: {
      ...$json,
      image_mime: "image/jpeg", // change to image/png if you requested PNG
      image_size_bytes: buffer.length,
    },
    binary: {
      image: await this.helpers.prepareBinaryData(buffer, "gemini-output.png", "image/jpeg"),
    },
  },
];

